#!/usr/bin/env node
/**
 * Post-build patch: rewrite the standalone `server.js` generated by
 * `next build --output standalone` so it is Phusion Passenger compatible.
 *
 * Problem
 * -------
 *   The generated server.js calls `startServer({ port, hostname, ... })`
 *   which always binds a TCP port (default 3000). Phusion Passenger (LiteSpeed
 *   on Hostinger Cloud Hosting Node) forks the app process and expects it to
 *   `listen()` on a Unix socket path passed as `process.argv[2]`. Result:
 *     - Worker logs "Ready on :3000" but Passenger sees nothing on its socket
 *     - Passenger respawn-loops the worker → 503 Service Unavailable upstream
 *
 * Fix
 * ---
 *   Replace the `startServer(...)` tail with a thin wrapper that:
 *     - keeps the injected nextConfig untouched
 *     - uses `next()` + `http.createServer(handle)` so we control `listen()`
 *     - if argv[2] is a path → Passenger Unix socket
 *     - otherwise → TCP `${HOSTNAME}:${PORT}` (local DX preserved)
 *
 * Idempotent: re-runs are safe (detects the marker line).
 *
 * Hostinger build pipeline runs `next build` from app/ ; this script is
 * invoked right after via the `build` script in package.json.
 */

'use strict'

const fs = require('fs')
const path = require('path')

// Hostinger build dir layout: app/.next/standalone/<outputFileTracingRoot>/server.js
// `outputFileTracingRoot` is the absolute root used by Next during the build.
// We just walk .next/standalone to find every server.js to be safe.
function findServerFiles(root) {
  const out = []
  if (!fs.existsSync(root)) return out
  const stack = [root]
  while (stack.length) {
    const dir = stack.pop()
    let entries
    try { entries = fs.readdirSync(dir, { withFileTypes: true }) } catch { continue }
    for (const e of entries) {
      const full = path.join(dir, e.name)
      if (e.isDirectory()) {
        if (e.name === 'node_modules') continue
        stack.push(full)
      } else if (e.isFile() && e.name === 'server.js') {
        out.push(full)
      }
    }
  }
  return out
}

const MARKER = '/* PATCHED-FOR-PASSENGER v1 */'

const PASSENGER_TAIL = `
${MARKER}
// Phusion Passenger (Hostinger Cloud Hosting Node + LiteSpeed) forks this
// process and passes a Unix socket path as argv[2]. If detected, listen on
// that socket. Otherwise fall back to TCP for local DX (\`node server.js\`).
const http = require('http')
const next = require('next')

const passengerSocket = process.argv[2]
const isPassenger =
  typeof passengerSocket === 'string' && passengerSocket.length > 0 && passengerSocket.startsWith('/')

const app = next({
  dir,
  dev: false,
  conf: nextConfig,
  hostname,
  port: currentPort,
  customServer: false,
})

app
  .prepare()
  .then(() => {
    const handle = app.getRequestHandler()
    const server = http.createServer((req, res) => handle(req, res))
    if (typeof keepAliveTimeout === 'number') {
      server.keepAliveTimeout = keepAliveTimeout
    }
    if (isPassenger) {
      // Clean any stale socket file from a previous worker (Passenger best-practice)
      try { require('fs').unlinkSync(passengerSocket) } catch (_) {}
      server.listen(passengerSocket, () => {
        // Passenger watches stdout for readiness via its own protocol;
        // a log line is harmless and useful for debugging via console.log
        console.log('▲ Next.js ready on Passenger socket ' + passengerSocket)
      })
    } else {
      server.listen(currentPort, hostname, () => {
        console.log('▲ Next.js ready on http://' + hostname + ':' + currentPort)
      })
    }
  })
  .catch((err) => {
    console.error(err)
    process.exit(1)
  })
`

function patchOne(file) {
  const src = fs.readFileSync(file, 'utf8')

  if (src.includes(MARKER)) {
    return { file, status: 'already-patched' }
  }

  // The generated server.js ends with:
  //   require('next')
  //   const { startServer } = require('next/dist/server/lib/start-server')
  //   if (Number.isNaN(keepAliveTimeout) ...) { keepAliveTimeout = undefined }
  //   startServer({ dir, isDev: false, config: nextConfig, hostname, port: currentPort, allowRetry: false, keepAliveTimeout })
  //     .catch((err) => { console.error(err); process.exit(1) })
  //
  // We replace everything from the `require('next')` line onwards.
  const cutMarker = "require('next')"
  const idx = src.indexOf(cutMarker)
  if (idx === -1) {
    return { file, status: 'cut-marker-not-found', error: true }
  }

  // Keep the prelude (path, dir, env, currentPort, hostname, keepAliveTimeout, nextConfig)
  // up to (but excluding) `require('next')`.
  const head = src.slice(0, idx)

  // Sanity: prelude must define dir, hostname, currentPort, keepAliveTimeout, nextConfig
  for (const sym of ['dir', 'hostname', 'currentPort', 'keepAliveTimeout', 'nextConfig']) {
    if (!new RegExp('\\b' + sym + '\\b').test(head)) {
      return { file, status: 'missing-symbol-' + sym, error: true }
    }
  }

  // Backup
  const bak = file + '.pre-passenger.bak'
  if (!fs.existsSync(bak)) fs.writeFileSync(bak, src)

  const next = head.trimEnd() + '\n' + PASSENGER_TAIL
  fs.writeFileSync(file, next)
  return { file, status: 'patched' }
}

function main() {
  const standalone = path.resolve(__dirname, '..', '.next', 'standalone')
  if (!fs.existsSync(standalone)) {
    console.log('[patch-server-passenger] no .next/standalone found, skipping')
    return
  }
  const files = findServerFiles(standalone)
  if (files.length === 0) {
    console.log('[patch-server-passenger] no server.js found under .next/standalone, skipping')
    return
  }
  let ok = 0, err = 0
  for (const f of files) {
    const r = patchOne(f)
    if (r.error) {
      err++
      console.error('[patch-server-passenger] FAIL', r.file, '-', r.status)
    } else {
      ok++
      console.log('[patch-server-passenger]', r.status, '-', r.file)
    }
  }
  if (err > 0) {
    console.error('[patch-server-passenger] ' + err + ' file(s) failed to patch')
    process.exit(1)
  }
  console.log('[patch-server-passenger] done (' + ok + ' file(s))')
}

main()
